mapper.select:
SELECT a.comcode as comCode, a.comname as comName, max(a.tjtime) as maxTjTime, sum(ck_jsl) as ckJsl, sum(ck_jsl_wcl) as ckJslWcl, sum(ck_wcl) as ckWcl, sum(ds_tjl) as dsTjl, sum(ds_wcl) as dsWcl, sum(ds_zfl) as dsZfl, sum(shougen) as shouGen, sum(hougen) as houGen, sum(tiaojie) as tiaoJie, sum(ja) as ja, sum(zl) as zl FROM acd_dangri_gzl_bm a WHERE a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
AND a.comname like concat('%', #{comName}, '%')
GROUP BY 1,2 ORDER BY comName desc

SELECT a.comcode as comCode, a.comname as comName, max(a.tjtime) as maxTjTime, sum(shougen) as shouGen, sum(hougen) as houGen, sum(tiaojie_zhuyuan) as tiaojieZhuyuan, sum(tiaojie_menzheng) as tiaojieMenzheng, sum(jiean_zhuyuan) as jieanZhuyuan, sum(jiean_mengzheng) as jieanMengzheng FROM acd_dangri_gzl_rs a WHERE a.tjdate >= #{startDate} AND a.tjdate <= #{endDate}
AND a.comname like concat('%', #{comName}, '%')
GROUP BY 1,2 ORDER BY comName desc

select tjdate, tjdate as maxTjTime, comcode_sgs, comname_sgs, chakan_zt, cuiding_zt, dingsun_zt, zhifu_zt, zhouqi_zt, zhouqi_wyn, zhouqi_wys from acd_zhouqi_qs where 1 = 1 and tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by zhouqi_zt desc

select tjdate, tjdate as maxTjTime, comcode_sgs, comname_sgs, khq, riskcode, jbf, pfcb, fy, glfy, cblr, zhcbl, zhfyl, zhpfl, jbf_qn, pfcb_qn, fy_qn, glfy_qn, cblr_qn, zhcbl_qn, zhfyl_qn, zhpfl_qn, zhcbl_tb, zhfyl_tb, zhpfl_tb from acd_zhpfl_khq where 1 = 1 and tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by zhpfl desc

select *, tjdate as maxTjTime from acd_pflsgn_zgs where tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by comcode_sgs, comcode

select *, tjdate as maxTjTime from acd_pflsgn_khq where tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by comcode_sgs

select *, tjdate as maxTjTime from acd_anjun_cx_zgs where tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by comcode_sgs, comcode

select *, tjdate as maxTjTime from acd_anjun_cx_khq where tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by comcode_sgs, khq

select *, tjdate as maxTjTime from acd_anjun_cx_xny where tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by comcode_sgs, xnyflag

select *, tjdate as maxTjTime from acd_pflsgn_xny where tjdate = #{tjDate}
and comname_sgs like concat('%', #{comnameSgs}, '%')
order by comcode_sgs, xnyflag
